Issue 「実装方針 3」のサンプルコードに ErrorBoundary 包含を追加:

```tsx
export function TerminalContainer({ history, terminal }: TerminalContainerProps) {
  const { visible, width, toggle, setWidth } = useHistoryPaneState();

  return (
    <div className="flex h-full min-h-0">
      {visible ? (
        <>
          <div id={HISTORY_PANE_ID} style={{ width: `${width}%` }} className="min-h-0">
            <ErrorBoundary componentName="HistoryPane">{history}</ErrorBoundary>
          </div>
          <PaneResizer onResize={setWidth} ariaValueNow={width} />
        </>
      ) : (
        <CollapsedExpandBar onExpand={toggle} />
      )}
      <div className="flex-1 min-h-0">
        <ErrorBoundary componentName="TerminalPane">{terminal}</ErrorBoundary>
      </div>
    </div>
  );
}
```

また受入条件「History 内包」に「History / Terminal 各々を ErrorBoundary でラップ（既存 WorktreeDesktopLayout の fault isolation 設計を継承）」を追加。

